record_types.code:
type Arp_Header is record
   Ar_Hdr      : Uint16;
   Ar_Pro      : Uint16;
   Ar_Hln      : Uint8;
   Ar_Pln      : Uint8;
   Ar_Op       : Uint16;
end record;

type Arp_Packet is record
   Ethernet : Net.Headers.Ether_Header;
   Arp      : Net.Headers.Ether_Arp;
end record;

type DHCP_Header is record
   Op     : Uint8;
   Htype  : Uint8;
   Hlen   : Uint8;
   Hops   : Uint8;
   Xid1   : Uint16;
   Xid2   : Uint16;
   Secs   : Uint16;
   Flags  : Uint16;
   Ciaddr : Ip_Addr;
   Yiaddr : Ip_Addr;
   Siaddr : Ip_Addr;
   Giaddr : Ip_Addr;
   Chaddr : String (1 .. 16);
   Sname  : String (1 .. 64);
   File   : String (1 .. 128);
end record;

type Ether_Arp is record
   Ea_Hdr      : Arp_Header;
   Arp_Sha     : Ether_Addr;
   Arp_Spa     : Ip_Addr;
   Arp_Tha     : Ether_Addr;
   Arp_Tpa     : Ip_Addr;
end record;

type Ether_Header is record
   Ether_Dhost : Ether_Addr;
   Ether_Shost : Ether_Addr;
   Ether_Type  : Uint16;
end record;

type ICMP_Header is record
   Icmp_Type     : Uint8;
   Icmp_Code     : Uint8;
   Icmp_Checksum : Uint16;
   Icmp_Id       : Uint16;
   Icmp_Seq      : Uint16;
end record;

type IGMP_Header is record
   Igmp_Type   : Uint8;
   Igmp_Code   : Uint8;
   Igmp_Cksum  : Uint16;
   Igmp_Group  : Ip_Addr;
end record;

type IP_Header is record
   Ip_Ihl      : Uint8;
   Ip_Tos      : Uint8;
   Ip_Len      : Uint16;
   Ip_Id       : Uint16;
   Ip_Off      : Uint16;
   Ip_Ttl      : Uint8;
   Ip_P        : Uint8;
   Ip_Sum      : Uint16;
   Ip_Src      : Ip_Addr;
   Ip_Dst      : Ip_Addr;
end record;

type TCP_Header is record
   Th_Sport    : Uint16;
   Th_Dport    : Uint16;
   Th_Seq      : Uint32;
   Th_Ack      : Uint32;
   Th_Off      : Uint8;
   Th_Flags    : Uint8;
   Th_Win      : Uint16;
   Th_Sum      : Uint16;
   Th_Urp      : Uint16;
end record;

type UDP_Header is record
   Uh_Sport    : Uint16;
   Uh_Dport    : Uint16;
   Uh_Ulen     : Uint16;
   Uh_Sum      : Uint16;
end record;
